const evi_err_msg = 'Something went wrong! Please try after sometime.';

function evidence_loader(count = '', df = false) {

    if( !df ) count = (count != '') ? ('Uploading: <span class="font-bold">'+ count +'%</span>') : 'Uploading...';
    return '<span class="evidence-upload-loader">'+ count +'</span>';
}

function upload_evidence(c_btn, container, res_container, form, fileInput, annex = false)
{
    // push answer id
    if( container.attr('data-ansid') != '' && container.attr('data-ansid') != 0 )
    {
        form.find('#evi_answer_id').val(container.attr('data-ansid'));
        form.find('#evi_annex_id').val( (container.attr('data-annexid') != undefined ) ? container.attr('data-annexid') : 0);
    }

    fileInput.click();
    var actionURL = $(form).attr("data-action");

    fileInput.off('change').on('change', function() {

        if (this.files.length > 0) {

            var eviFile = this.files[0];

            // check file type and size // Check if file is selected
            if (!eviFile) {
                $( res_container ).html('<span class="d-block text-danger font-sm mt-2">Please select a file.</span>');
                return;
            }

            if (!evi_file_type.includes(eviFile.type)) {
                $( res_container ).html('<span class="d-block text-danger font-sm mt-2">Only '+ evi_file_type +' files are allowed.</span>');
                return;
            }

            var eviMaxSize = evi_file_size * 1024 * 1024; // 10 MB (adjust as needed)

            if (eviFile.size > eviMaxSize) {
                $( res_container ).html('<span class="d-block text-danger font-sm mt-2">File size exceeds the maximum limit of '+ evi_file_size +' MB.</span>');
                return;
            }
            
            var formData = new FormData(form[0]);

            if(annex) formData.append('evi_annex', true);

            $( res_container ).html( evidence_loader('0') );

            $.ajax({
                url: actionURL,
                type: 'POST',
                data: formData,
                contentType: false,
                processData: false,
                xhr: function() {
                    var xhr = new window.XMLHttpRequest();
                    xhr.upload.addEventListener('progress', function(e) {
                        if (e.lengthComputable) {
                            var percentComplete = e.loaded / e.total * 100;
                            $( res_container ).html( evidence_loader(percentComplete) );
                        }
                    }, false);
                    return xhr;
                },

                success: function(res) {

                    try 
                    {
                        res = JSON.parse(res);
                
                        // has error
                        if(res.err)
                            $( res_container ).html('<span class="d-block text-danger font-sm mt-2">'+ res.msg +'</span>');
                        else
                        {
                            // display markup
                            $( res_container ).html(res.markup);
                            c_btn.hide();
                        }

                    } 
                    catch (error) { alert(evi_err_msg); }
                },
                
                error: function() { alert(evi_err_msg); }
            });
        }

        fileInput.val('');
        form.find('#evi_answer_id').val('');
        form.find('#evi_annex_id').val('');
    });
}

